import { readFileSync } from "node:fs";
import { quote } from "./claim-office.js";

const input = readFileSync(0, "utf-8");
const { customer, steps } = JSON.parse(input);
const results = steps.map((step: { op: string; items: { type: string }[] }) => {
  if (step.op === "quote") {
    return { premium: quote(customer, step.items) };
  }
  return {};
});
process.stdout.write(JSON.stringify({ results }));
